#include <bits/stdc++.h>
using namespace std;

const int N=1500,M=240000,INF=2e9;

int n,m,s,t,S,T;
int head[N],ver[M],edge[M],nxt[M],tot;
int du[N],d[N],now[N];
int lg[N],rg[N];
bool vis[N];

void add(int x,int y,int l,int r){
	//cout<<x<<' '<<y<<" ["<<l<<','<<r<<"]\n";
    du[x]-=l,du[y]+=l;
    ver[++tot]=y,edge[tot]=r-l,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(S),d[S]=1,now[S]=head[S];
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==T)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==T)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(flow-res,edge[i]));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(0),cout.tie(0);
    while(cin>>n>>m){
        tot=1,s=n+m+1,t=n+m+2;
        memset(head,0,sizeof(head));
        memset(du,0,sizeof(du));
        for(int i=1,g;i<=m;i++){
            cin>>g;
            add(s,i,g,INF);
        }
        for(int i=1;i<=n;i++){
            int x,y;
            vector<int> pg;
            cin>>x>>y;
            add(i+m,t,0,y);
            for(int j=1,to,l,r;j<=x;j++){
                cin>>to>>l>>r;
                add(++to,i+m,l,r);
            }
            //cout<<'\n';
        }
        //cout<<flag<<'\n';
        add(t,s,0,INF);
        S=m+n+3,T=m+n+4;
        int sum=0,flow;
        for(int i=1;i<=m+n+2;i++)
            if(du[i]>0)
                add(S,i,0,du[i]),sum+=du[i];
            else if(du[i]<0)
                add(i,T,0,-du[i]);
        while(bfs())
            while(flow=Dinic(S,INF))
                sum-=flow;
        //cout<<sum<<'\n';
        if(sum){
            cout<<"-1\n\n";
            continue;
        }
        S=s,T=t;
        while(bfs())
            while(flow=Dinic(S,INF))
                sum+=flow;
        cout<<sum<<"\n\n";
    }
    return 0;
}
